/**
 * Cities that share a name across multiple states.
 * Maps (city + state) → the qualified key used in cityPh.
 */
const AMBIGUOUS_CITIES: Record<string, string> = {
  "Bilaspur|Himachal Pradesh": "Bilaspur (HP)",
  "Bilaspur|Chhattisgarh": "Bilaspur",
  "Aurangabad|Bihar": "Aurangabad (Bihar)",
  "Aurangabad|Maharashtra": "Aurangabad",
  "Srinagar|Jammu and Kashmir": "Srinagar",
  "Srinagar|Uttarakhand": "Srinagar (UK)",
  "Udaipur|Rajasthan": "Udaipur",
  "Udaipur|Tripura": "Udaipur (Tripura)",
};

/**
 * Lookup pH data for a city.
 * Pass the plot's state string to correctly resolve cities that appear in multiple states.
 * Falls back to a safe default if city is not in the dataset.
 */
export function getCityPh(city: string, state?: string): CityPh {
  // Try to resolve ambiguous city names first
  const qualifiedKey = state ? AMBIGUOUS_CITIES[`${city}|${state}`] : undefined;
  const lookupKey = qualifiedKey ?? city;

  return (
    cityPh[lookupKey] ?? {
      ph: 6.8,
      type: "Slightly Acidic",
      note: "Default estimate — city not found in database.",
    }
  );
}

